judgeConfig.referenceSolution:
export class QueryBuilder<T> {
  private data: T[];
  private filters: Array<(row: T) => boolean> = [];
  private selectedKeys: Array<keyof T> = [];

  constructor(data: T[]) {
    this.data = data;
  }

  where<K extends keyof T>(column: K, operator: '==' | '>', value: T[K]): this {
    this.filters.push((row: T) => {
      const cell = row[column];
      if (operator === '==') return cell === value;
      if (operator === '>') return cell > value;
      return false;
    });
    return this;
  }

  select<K extends keyof T>(...keys: K[]): QueryBuilder<Pick<T, K>> {
    const next = new QueryBuilder<any>(this.data);
    next.filters = [...this.filters];
    next.selectedKeys = keys;
    return next;
  }

  execute(): T[] {
    let result = this.data.filter(row => this.filters.every(fn => fn(row)));
    if (this.selectedKeys.length > 0) {
      result = result.map(row => {
        const projection: any = {};
        this.selectedKeys.forEach(k => {
          projection[k] = row[k];
        });
        return projection;
      });
    }
    return result;
  }
}
